| MCP:XRuYwm | plugins {
| MCP:XRuYwm |     id 'java-library'
| MCP:XRuYwm |     id 'org.springframework.boot' apply(false)
| MCP:XRuYwm |     id 'io.spring.dependency-management'
| MCP:XRuYwm |     id 'io.spring.javaformat' apply(false)
| MCP:XRuYwm |     id 'org.asciidoctor.jvm.convert' apply(false)
| MCP:XRuYwm | }
| MCP:XRuYwm | 
| MCP:XRuYwm | apply from: 'lint.gradle'
| MCP:XRuYwm | 
| MCP:XRuYwm | allprojects {
| MCP:XRuYwm |     group = "${projectGroup}"
| MCP:XRuYwm |     version = "${applicationVersion}"
| MCP:XRuYwm | 
| MCP:XRuYwm |     repositories {
| MCP:XRuYwm |         mavenCentral()
| MCP:XRuYwm |     }
| MCP:XRuYwm | }
| MCP:XRuYwm | 
| MCP:XRuYwm | subprojects {
| MCP:XRuYwm |     apply plugin: 'java-library'
| MCP:XRuYwm |     apply plugin: 'org.springframework.boot'
| MCP:XRuYwm |     apply plugin: 'io.spring.dependency-management'
| MCP:XRuYwm |     apply plugin: 'org.asciidoctor.jvm.convert'
| MCP:XRuYwm |     
| MCP:XRuYwm |     dependencyManagement {
| MCP:XRuYwm |         imports {
| MCP:XRuYwm |             mavenBom "org.springframework.cloud:spring-cloud-dependencies:${springCloudDependenciesVersion}"
| MCP:XRuYwm |         }
| MCP:XRuYwm |     }
| MCP:XRuYwm | 
| MCP:XRuYwm |     dependencies {
| MCP:XRuYwm |         annotationProcessor 'org.springframework.boot:spring-boot-configuration-processor'
| MCP:XRuYwm |         testImplementation 'org.springframework.boot:spring-boot-test'
| MCP:XRuYwm |         testImplementation 'org.junit.jupiter:junit-jupiter-api'
| MCP:XRuYwm |         testImplementation 'org.junit.jupiter:junit-jupiter-engine'
| MCP:XRuYwm |         testRuntimeOnly 'org.junit.platform:junit-platform-launcher'
| MCP:XRuYwm |         testImplementation 'org.assertj:assertj-core'
| MCP:XRuYwm |         testImplementation 'org.mockito:mockito-core'
| MCP:XRuYwm |     }
| MCP:XRuYwm | 
| MCP:XRuYwm |     java {
| MCP:XRuYwm |         toolchain {
| MCP:XRuYwm |             languageVersion = JavaLanguageVersion.of(project.javaVersion)
| MCP:XRuYwm |         }
| MCP:XRuYwm |     }
| MCP:XRuYwm | 
| MCP:XRuYwm |     bootJar.enabled = false
| MCP:XRuYwm |     jar.enabled = true
| MCP:XRuYwm | 
| MCP:XRuYwm |     test {
| MCP:XRuYwm |         useJUnitPlatform {
| MCP:XRuYwm |             excludeTags 'develop', 'restdocs'
| MCP:XRuYwm |         }
| MCP:XRuYwm |     }
| MCP:XRuYwm | 
| MCP:XRuYwm |     testing {
| MCP:XRuYwm |         suites {
| MCP:XRuYwm |             test {
| MCP:XRuYwm |                 targets {
| MCP:XRuYwm |                     unitTest {
| MCP:XRuYwm |                         testTask.configure {
| MCP:XRuYwm |                             group = 'verification'
| MCP:XRuYwm |                             useJUnitPlatform {
| MCP:XRuYwm |                                 excludeTags 'develop', 'context', 'restdocs'
| MCP:XRuYwm |                             }
| MCP:XRuYwm |                         }
| MCP:XRuYwm |                     }
| MCP:XRuYwm | 
| MCP:XRuYwm |                     contextTest {
| MCP:XRuYwm |                         testTask.configure {
| MCP:XRuYwm |                             group = 'verification'
| MCP:XRuYwm |                             useJUnitPlatform {
| MCP:XRuYwm |                                 includeTags 'context'
| MCP:XRuYwm |                             }
| MCP:XRuYwm |                         }
| MCP:XRuYwm |                     }
| MCP:XRuYwm | 
| MCP:XRuYwm |                     restDocsTest {
| MCP:XRuYwm |                         testTask.configure {
| MCP:XRuYwm |                             group = 'verification'
| MCP:XRuYwm |                             useJUnitPlatform {
| MCP:XRuYwm |                                 includeTags 'restdocs'
| MCP:XRuYwm |                             }
| MCP:XRuYwm |                         }
| MCP:XRuYwm |                     }
| MCP:XRuYwm | 
| MCP:XRuYwm |                     developTest {
| MCP:XRuYwm |                         testTask.configure {
| MCP:XRuYwm |                             group = 'verification'
| MCP:XRuYwm |                             useJUnitPlatform {
| MCP:XRuYwm |                                 includeTags 'develop'
| MCP:XRuYwm |                             }
| MCP:XRuYwm |                         }
| MCP:XRuYwm |                     }
| MCP:XRuYwm |                 }
| MCP:XRuYwm |             }
| MCP:XRuYwm |         }
| MCP:XRuYwm |     }
| MCP:XRuYwm | 
| MCP:XRuYwm |     tasks.named('asciidoctor').configure {
| MCP:XRuYwm |         dependsOn restDocsTest
| MCP:XRuYwm |     }
| MCP:XRuYwm | }
